    const n = nums.length;

    // Precompute prefix maximums: maxPrefix[i] = max(nums[0...i])
    const maxPrefix = new Array(n);
    let currentMax = -Infinity;
    for (let i = 0; i < n; i++) {
        currentMax = Math.max(currentMax, nums[i]);
        maxPrefix[i] = currentMax;
    }

    // Precompute suffix minimums: minSuffix[i] = min(nums[i...n-1])
    const minSuffix = new Array(n);
    let currentMin = Infinity;
    for (let i = n - 1; i >= 0; i--) {
        currentMin = Math.min(currentMin, nums[i]);
        minSuffix[i] = currentMin;
    }

    // Iterate through all indices i and check the condition
    for (let i = 0; i < n; i++) {
        // Unstable value = max(nums[0...i]) - min(nums[i...n-1])
        const unstableValue = maxPrefix[i] - minSuffix[i];

        // Check if the index is stable
        if (unstableValue <= k) {
            // Return the smallest stable index found
            return i;
        }
    }

    // If no stable index is found
    return -1;
}

